import React, { useEffect, useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { RNIap, purchaseErrorListener, purchaseUpdatedListener } from 'react-native-iap';
import DeviceInfo from 'react-native-device-info';

const paymentModule = () => {
  const [products, setProducts] = useState([]);
  const [isDeviceSecure, setIsDeviceSecure] = useState(false);

  useEffect(() => {
    const initIAP = async () => {
      try {
        await RNIap.initConnection();
        const productIds = ['product_id_1', 'product_id_2'];
        const products = await RNIap.getProducts(productIds);
        setProducts(products);
      } catch (err) {
        console.warn(err);
      }
    };

    const checkDeviceIntegrity = async () => {
      const isEmulator = await DeviceInfo.isEmulator();
      const isRooted = await DeviceInfo.isRooted();
      setIsDeviceSecure(!isEmulator && !isRooted);
    };

    initIAP();
    checkDeviceIntegrity();

    const purchaseUpdateSubscription = purchaseUpdatedListener((purchase) => {
      // Handle successful purchase
      Alert.alert('Purchase Successful', `Product: ${purchase.productId}`);
    });

    const purchaseErrorSubscription = purchaseErrorListener((error) => {
      // Handle purchase error
      Alert.alert('Purchase Error', error.message);
    });

    return () => {
      purchaseUpdateSubscription.remove();
      purchaseErrorSubscription.remove();
      RNIap.endConnection();
    };
  }, []);

  const requestPurchase = async (productId) => {
    if (!isDeviceSecure) {
      Alert.alert('Security Alert', 'Device integrity check failed.');
      return;
    }
    try {
      await RNIap.requestPurchase(productId);
    } catch (err) {
      Alert.alert('Purchase Error', err.message);
    }
  };

  return (
    <View>
      {products.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title}`}
          onPress={() => requestPurchase(product.productId)}
        />
      ))}
    </View>
  );
};

export default paymentModule;